import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.content.Context
import android.content.SharedPreferences
import android.hardware.biometrics.BiometricManager
import android.hardware.fingerprint.FingerprintManager
import android.os.CancellationSignal
import androidx.core.hardware.fingerprint.FingerprintManagerCompat
import android.util.Patterns
import android.widget.Toast
import androidx.appcompat.app.AlertDialog

class MainActivity : AppCompatActivity() {

 private lateinit var sharedPreferences: SharedPreferences

 override fun onCreate(savedInstanceState: Bundle?) {
 super.onCreate(savedInstanceState)
 setContentView(R.layout.activity_main)

 sharedPreferences = getSharedPreferences("AUTHENTICATED", Context.MODE_PRIVATE)

 val biometricManager = BiometricManager.from(this)
 when (biometricManager.canAuthenticate) {
 BiometricManager.BIOMETRIC_SUCCESS -> setUpBiometricPrompt()
 BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> Toast.makeText(
 this, "Fingerprint scanner is not available", Toast.LENGTH_SHORT).show()
 BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> Toast.makeText(
 this, "Your device does not have a fingerprint scanner", Toast.LENGTH_SHORT).show()
 BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
 val builder = AlertDialog.Builder(this)
 with(builder) {
 setTitle("Fingerprint setup")
 setMessage("Please set up your fingerprint first.")
 setPositiveButton("Ok") { _, _ -> startActivity(Intent(Settings.ACTION_FINGERPRINT_SETTINGS)) }
 create().show()
 }
 }
 }
 }

 private fun setUpBiometricPrompt() {
 val execution = Executors.newSingleThreadExecutor()
 val work = Runnable {
 val fingerprintManager = FingerprintManagerCompat.from(this)
 val keyGuardManager = getSystemService(Context.KEYGUARD_SERVICE) as KeyguardManager

 if (!keyGuardManager.isKeyguardSecure) {
 Toast.makeText(this, "Your device needs to be secured for fingerprint recognition", Toast.LENGTH_SHORT).show()
 return@Runnable
 }

 val cryptObject = fingerprintManager.newCryptObject(fingerprintManager.cryptoObject)
 val promptInfo = FingerprintManagerCompat.Builder(this, cryptObject)
 .setTitle("Authentication required")
 .setSubtitle("Please verify your identity")
 .build()

 val authenticationCallback = object : FingerprintManagerCompat.AuthenticationCallback() {
 override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
 super.onAuthenticationError(errorCode, errString)
 Toast.makeText(this@MainActivity, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
 if (shouldBypassLogin()) startActivity(Intent(this@MainActivity, LoginActivity::class.java))
 }

 override fun onAuthenticationHelp(helpCode: Int, helpString: CharSequence) {
 super.onAuthenticationHelp(helpCode, helpString)
 Toast.makeText(this@MainActivity, "Authentication help: $helpString", Toast.LENGTH_SHORT).show()
 }

 override fun onAuthenticationSucceeded(result: FingerprintManager.CryptoObject) {
 super.onAuthenticationSucceeded(result)
 with(SharedPreferences.Editor.create(sharedPreferences)) {
 putBoolean("authenticated", true)
 apply()
 }
 Toast.makeText(this@MainActivity, "Authentication succeeded", Toast.LENGTH_SHORT).show()
 startActivity(Intent(this@MainActivity, MainActivity::class.java))
 finish()
 }

 override fun onAuthenticationFailed() {
 super.onAuthenticationFailed()
 Toast.makeText(this@MainActivity, "Authentication failed", Toast.LENGTH_SHORT).show()
 if (shouldBypassLogin()) startActivity(Intent(this@MainActivity, LoginActivity::class.java))
 }
 }

 val cancellationSignal = CancellationSignal()
 FingerprintManagerCompat.authenticate(fingerprintManager, promptInfo, authenticationCallback, cancellationSignal)
 execution.shutdown()
 }

 private fun shouldBypassLogin(): Boolean {
 return sharedPreferences.getBoolean("authenticated", false)
 }
}